function openedPopup() {
  notOpen = !1;
}
function closedpopup() {
  notOpen = !0;
}
$(".flightPop").click(function () {
  return (
    (notOpen = !1),
    $.featherlight("#loadModal-lastchance", {
      afterClose: closedpopup,
      afterOpen: openedPopup,
      openSpeed: 0,
      closeSpeed: 0,
    }),
    !1
  );
}),
  
function locateScrollElement(e) {
  e = $("#" + e).offset().top;
  $("html, body").animate({ scrollTop: e }, 1e3);
}
$(".rebill-clickbox").on("click", function (e) {
  $(".rebill-checkbox2").toggleClass("rebill-checkbox2-clicked"),
    $(".rebill-checkbox2").hasClass("rebill-checkbox2-clicked")
      ? ($(".rebill-clickbox").removeClass("rebill-clickbox-red"),
        $(".rebill-checkbox2").removeClass("pulsing2"),
        $(".rebill-checkbox2").removeClass("rebill-checkbox2-animation"),
        $(".rebill-clickbox").addClass("rebill-clickbox-green"))
      : ($(".rebill-checkbox2").addClass("rebill-checkbox2-animation"),
        $(".rebill-checkbox2").addClass("pulsing2"),
        $(".rebill-clickbox").removeClass("rebill-clickbox-green"));
}),
  $(".confirm-rebill").on("click", function (e) {
    return (
      !!$(".rebill-checkbox2").hasClass("rebill-checkbox2-clicked") ||
      (e.preventDefault(),
      $(".rebill-clickbox").addClass("rebill-clickbox-red"),
      locateScrollElement("AddToOrder"),
      void alert(
        "You need to first click the green box to accept the payment terms!"
      ))
    );
  });
